fn array_and_vec() -> ([i32; 4], Vec<i32>) {
    let a = [10, 20, 30, 40];

    let v = vec![10, 20, 30, 40];

    (a, v)
}

fn main() {
    let (a, v) = array_and_vec();
    assert_eq!(a, v[..]);
    println!("Arrays and vectors look the same: {:?} vs {:?}", a, v);
}
